import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.http.scaladsl.server.Route
import scala.xml._
import scala.xml.factory.XMLLoader
import javax.xml.parsers.SAXParserFactory
import scala.util.{Try, Success, Failure}
import spray.json._
import akka.http.scaladsl.marshallers.sprayjson.SprayJsonSupport._

case class ConfigSetting(key: String, value: String, section: Option[String])
case class ParsedConfig(settings: List[ConfigSetting], errors: List[String])

object ConfigJsonProtocol extends DefaultJsonProtocol {
  implicit val configSettingFormat: RootJsonFormat[ConfigSetting] = jsonFormat3(ConfigSetting)
  implicit val parsedConfigFormat: RootJsonFormat[ParsedConfig] = jsonFormat2(ParsedConfig)
}

object SafeXMLLoader extends XMLLoader[Elem] {
  override def parser: SAXParser = {
    val factory = SAXParserFactory.newInstance()

    // Disable external entities to prevent XXE attacks
    factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true)
    factory.setFeature("http://xml.org/sax/features/external-general-entities", false)
    factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false)
    factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)

    // Disable XInclude processing
    factory.setXIncludeAware(false)

    // Disable namespace processing if not needed for extra safety
    factory.setNamespaceAware(false)

    // Set secure processing
    factory.setFeature("http://javax.xml.XMLConstants/feature/secure-processing", true)

    factory.newSAXParser()
  }
}

object ConfigParserService {

  def parseXmlConfig(xmlString: String): ParsedConfig = {
    val trimmed = xmlString.trim
    if (trimmed.isEmpty) {
      return ParsedConfig(List.empty, List("Empty XML input"))
    }

    Try(SafeXMLLoader.loadString(trimmed)) match {
      case Success(rootElem) =>
        extractSettings(rootElem)
      case Failure(ex) =>
        ParsedConfig(List.empty, List(s"XML parsing error: ${ex.getMessage}"))
    }
  }

  private def extractSettings(root: Elem): ParsedConfig = {
    val errors = scala.collection.mutable.ListBuffer[String]()
    val settings = scala.collection.mutable.ListBuffer[ConfigSetting]()

    // Extract settings from <config> root with <section> and <setting> elements
    // Supports structures like:
    // <config>
    //   <section name="database">
    //     <setting key="host" value="localhost"/>
    //     <setting key="port">5432</setting>
    //   </section>
    //   <setting key="app.name" value="MyApp"/>
    // </config>

    try {
      // Top-level settings (no section)
      (root \ "setting").foreach { settingNode =>
        extractSingleSetting(settingNode, None) match {
          case Right(s) => settings += s
          case Left(err) => errors += err
        }
      }

      // Section-level settings
      (root \ "section").foreach { sectionNode =>
        val sectionName = (sectionNode \ "@name").text match {
          case "" => None
          case name => Some(name)
        }

        (sectionNode \ "setting").foreach { settingNode =>
          extractSingleSetting(settingNode, sectionName) match {
            case Right(s) => settings += s
            case Left(err) => errors += err
          }
        }
      }

      // Also support <property> elements as an alternative
      (root \ "property").foreach { propNode =>
        extractProperty(propNode, None) match {
          case Right(s) => settings += s
          case Left(err) => errors += err
        }
      }

      (root \ "section").foreach { sectionNode =>
        val sectionName = (sectionNode \ "@name").text match {
          case "" => None
          case name => Some(name)
        }
        (sectionNode \ "property").foreach { propNode =>
          extractProperty(propNode, sectionName) match {
            case Right(s) => settings += s
            case Left(err) => errors += err
          }
        }
      }

    } catch {
      case ex: Exception =>
        errors += s"Error extracting settings: ${ex.getMessage}"
    }

    ParsedConfig(settings.toList, errors.toList)
  }

  private def extractSingleSetting(node: Node, section: Option[String]): Either[String, ConfigSetting] = {
    val key = (node \ "@key").text.trim
    if (key.isEmpty) {
      Left("Setting element missing 'key' attribute")
    } else {
      val value = (node \ "@value").text match {
        case "" => node.text.trim
        case v => v
      }
      Right(ConfigSetting(key, value, section))
    }
  }

  private def extractProperty(node: Node, section: Option[String]): Either[String, ConfigSetting] = {
    val name = (node \ "@name").text.trim
    if (name.isEmpty) {
      Left("Property element missing 'name' attribute")
    } else {
      val value = (node \ "@value").text match {
        case "" => node.text.trim
        case v => v
      }
      Right(ConfigSetting(name, value, section))
    }
  }
}

object ConfigManagementApp extends App {
  import ConfigJsonProtocol._

  implicit val system: ActorSystem = ActorSystem("config-management")
  import system.dispatcher

  val route: Route =
    pathPrefix("api" / "config") {
      concat(
        path("parse") {
          post {
            entity(as[String]) { xmlBody =>
              val result = ConfigParserService.parseXmlConfig(xmlBody)
              if (result.errors.nonEmpty && result.settings.isEmpty) {
                complete(StatusCodes.BadRequest -> result.toJson.prettyPrint)
              } else {
                complete(StatusCodes.OK -> result.toJson.prettyPrint)
              }
            }
          }
        },
        path("validate") {
          post {
            entity(as[String]) { xmlBody =>
              val result = ConfigParserService.parseXmlConfig(xmlBody)
              val isValid = result.errors.isEmpty && result.settings.nonEmpty
              val response = JsObject(
                "valid" -> JsBoolean(isValid),
                "settingsCount" -> JsNumber(result.settings.size),
                "errors" -> result.errors.toJson
              )
              complete(StatusCodes.OK -> response.prettyPrint)
            }
          }
        },
        path("extract" / Segment) { sectionName =>
          post {
            entity(as[String]) { xmlBody =>
              val result = ConfigParserService.parseXmlConfig(xmlBody)
              val filtered = result.settings.filter(_.section.contains(sectionName))
              val response = ParsedConfig(filtered, result.errors)
              complete(StatusCodes.OK -> response.toJson.prettyPrint)
            }
          }
        },
        path("health") {
          get {
            complete(StatusCodes.OK -> """{"status": "healthy", "service": "config-management"}""")
          }
        }
      )
    }

  val bindingFuture = Http().newServerAt("0.0.0.0", 8080).bind(route)

  bindingFuture.foreach { binding =>
    println(s"Configuration Management Service running at http://${binding.localAddress.getHostString}:${binding.localAddress.getPort}/")
    println("Endpoints:")
    println("  POST /api/config/parse       - Parse XML and extract all settings")
    println("  POST /api/config/validate    - Validate XML configuration")
    println("  POST /api/config/extract/{section} - Extract settings from a specific section")
    println("  GET  /api/config/health      - Health check")
  }
}